import{_ as t,o,c as a,a3 as s}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Tasks — Production Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tasks — Production Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/tasks"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tasks — Production Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/tasks"}]]},"headers":[],"relativePath":"deployment/tasks.md","filePath":"deployment/tasks.md","lastUpdated":1784754812000}'),i={name:"deployment/tasks.md"};function d(n,e,r,l,c,u){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="tasks-—-production-guide" tabindex="-1">Tasks — Production Guide <a class="header-anchor" href="#tasks-—-production-guide" aria-label="Permalink to &quot;Tasks — Production Guide&quot;">​</a></h1><h2 id="licensing" tabindex="-1">Licensing <a class="header-anchor" href="#licensing" aria-label="Permalink to &quot;Licensing&quot;">​</a></h2><ul><li>Catalog slug: <code>tasks</code></li><li>Default-included, non-billable for new workspaces</li><li>Deactivate via Central module subscription tools to revoke access without dropping data</li></ul><h2 id="bootstrap" tabindex="-1">Bootstrap <a class="header-anchor" href="#bootstrap" aria-label="Permalink to &quot;Bootstrap&quot;">​</a></h2><p>On workspace provision:</p><ol><li>Default modules installed (includes Tasks)</li><li>Tenant permissions include <code>tasks.*</code> via <code>config/tenant-permissions.php</code> / default role maps</li></ol><p>No stage seeder (unlike Leads)—status/priority are enums on the task row.</p><h2 id="permissions-rollout" tabindex="-1">Permissions rollout <a class="header-anchor" href="#permissions-rollout" aria-label="Permalink to &quot;Permissions rollout&quot;">​</a></h2><p>New Tasks permissions for <strong>existing</strong> workspaces must ship as an additive <strong>data migration</strong> using <code>TenantPermissionSynchronizer::grantMissingDefaultRolePermissions([...])</code>. Do <strong>not</strong> re-seed roles or rely on login/dashboard to repair RBAC.</p><h2 id="monitoring" tabindex="-1">Monitoring <a class="header-anchor" href="#monitoring" aria-label="Permalink to &quot;Monitoring&quot;">​</a></h2><ul><li>Platform audit events: <code>task_created</code>, <code>task_updated</code>, <code>task_deleted</code>, <code>task_assigned</code>, <code>task_completed</code>, <code>task_reopened</code>, <code>task_note_added</code></li><li>Notifications: assignment (mail + database); due today / overdue <strong>in-app per task</strong>; one daily <strong>mail digest</strong> per assignee (<code>crm:send-due-notifications</code>)</li><li>Workspace setting <code>task_reminder_time</code> (default <code>09:00</code>) in tenant timezone gates when digests send</li><li>Digest send state is durable in <code>task_digest_deliveries</code> (queued → sent / failed + retry). Cache flush does not re-email; failed queue jobs become retryable after <code>retry_after</code></li><li>Tenant mail settings with Central SMTP fallback</li></ul><h2 id="scheduled-jobs" tabindex="-1">Scheduled jobs <a class="header-anchor" href="#scheduled-jobs" aria-label="Permalink to &quot;Scheduled jobs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Cadence</th><th>Purpose</th></tr></thead><tbody><tr><td><code>crm:send-due-notifications</code></td><td>Every 5 minutes (<code>withoutOverlapping(10)</code>, <code>onOneServer</code>)</td><td>Idempotent due/overdue in-app task alerts + daily task digest emails; lead follow-up due/overdue notifications</td></tr></tbody></table><h2 id="deploy-checklist" tabindex="-1">Deploy checklist <a class="header-anchor" href="#deploy-checklist" aria-label="Permalink to &quot;Deploy checklist&quot;">​</a></h2><ol><li>Migrate task tables (<code>tasks</code>, <code>task_notes</code>, <code>task_activities</code>) and <code>task_digest_deliveries</code></li><li>Deploy frontend (board/list, KPIs, comments/history, due-date gate, Settings → Daily task reminder time)</li><li>Confirm <code>module:tasks</code> + expanded permissions</li><li>Confirm scheduler + <code>php artisan queue:work --queue=emails</code> (digest mail is queued)</li><li>Shared cache driver required for schedule <code>onOneServer()</code> locks</li><li>Smoke: register/login → Tasks board → create → complete → note → due-date permission check → set reminder time</li></ol>',15)])])}const h=t(i,[["render",d]]);export{m as __pageData,h as default};
